use std::collections::HashMap;

#[derive(Eq, Hash, PartialEq, Copy, Clone)]
struct ConnectionId(u64);

struct RateLimiter {
    usage_map: HashMap<ConnectionId, u64>,
    capacity: u64,
}

impl RateLimiter {
    fn new(capacity: u64) -> Self {
        RateLimiter {
            usage_map: HashMap::new(),
            capacity,
        }
    }

    fn check_and_increment(&mut self, id: ConnectionId, amount: u64) -> bool {
        if let Some(current_usage) = self.usage_map.get_mut(&id) {
            if *current_usage + amount > self.capacity {
                return false;
            }
            *current_usage += amount;
            true
        } else if amount <= self.capacity {
            self.usage_map.insert(id, amount);
            true
        } else {
            false
        }
    }
}

trait TrafficShaper {
    fn get_limiter(&mut self) -> &mut RateLimiter;
}

struct ProxyHandler { 
    shaper: RateLimiter,
}

impl TrafficShaper for ProxyHandler {
    fn get_limiter(&mut self) -> &mut RateLimiter {
        &mut self.shaper
    }
}

fn main() {
    let mut handler = ProxyHandler { 
        shaper: RateLimiter::new(100),
    };
    let conn_a = ConnectionId(1);
    let conn_b = ConnectionId(2);

    if handler.get_limiter().check_and_increment(conn_a, 30) && 
       handler.get_limiter().check_and_increment(conn_b, 50) {
        println!("Both connections passed initial checks.");
    }

    if !handler.get_limiter().check_and_increment(conn_a, 80) {
        println!("Connection A hit its limit on the second check!");
    }
}

use std::collections::HashMap;
use std::fmt::Debug;

trait Action { 
    fn execute(&self, context: &str) -> String;
}

struct Square { 
    id: u32,
}

impl Action for Square { 
    fn execute(&self, _: &str) -> String {
        format!("Square {} executed successfully.", self.id)
    }
}

struct LineClearer { 
    value: i32,
}

impl Action for LineClearer { 
    fn execute(&self, _: &str) -> String {
        format!("Cleared {} lines worth of debris.", self.value)
    }
}

struct BotEngine {
    actions: HashMap<String, Box<dyn Action + Send + Sync>>,
}

impl BotEngine {
    fn new() -> Self {
        let mut actions = HashMap::new();
        actions.insert("square".to_string(), Box::new(Square { id: 101 }) as Box<dyn Action + Send + Sync>);
        actions.insert("clear".to_string(), Box::new(LineClearer { value: 5 }) as Box<dyn Action + Send + Sync>);
        BotEngine {
            actions,
        }
    }

    fn run_action(&self, name: &str, context: &str) -> Option<String> {
        if let Some(action) = self.actions.get(name) {
            Some(action.execute(context))
        } else {
            None
        }
    }
}

fn main() {
    let bot = BotEngine::new();
    let context_data = "Game state snapshot";

    if let Some(result) = bot.run_action("square", context_data) {
        println!("Result 1: {}", result);
    }

    if let Some(result) = bot.run_action("clear", context_data) {
        println!("Result 2: {}", result);
    }

    let unknown_action = "invalid";
    match bot.run_action(unknown_action, context_data) {
        Some(result) => println!("Unexpected success for {}: {}", unknown_action, result),
        None => println!("Correctly failed to execute unknown action: {}", unknown_action),
    }
}

use std::collections::HashMap;
use std::sync::{Arc, Mutex};

struct MessageLog {
    logs: HashMap<String, Vec<String>>
}
impl MessageLog {
    fn new() -> Self {
        MessageLog { logs: HashMap::new() }
    }
    fn add_message(&mut self, user_id: &str, message: String) {
        self.logs.entry(user_id.to_string()).or_default().push(message);
    }
}

fn main() {
    let log = Arc::new(Mutex::new(MessageLog::new()));

    let handle1 = { 
        let log_clone = Arc::clone(&log);
        std::thread::spawn(move || {
            log_clone.lock().unwrap().add_message("Alice", "Hi there".to_string());
            std::thread::sleep(std::time::Duration::from_millis(50));
            log_clone.lock().unwrap().add_message("Bob", "Hey".to_string());
        })
    };

    let handle2 = { 
        let log_clone = Arc::clone(&log);
        std::thread::spawn(move || {
            std::thread::sleep(std::time::Duration::from_millis(10));
            log_clone.lock().unwrap().add_message("Alice", "How are you".to_string());
            std::thread::sleep(std::time::Duration::from_millis(50));
            log_clone.lock().unwrap().add_message("Charlie", "Bye".to_string());
        })
    };

    handle1.join().unwrap();
    handle2.join().unwrap();

    let final_log = log.lock().unwrap();
    println!("--- Final Message Log ---n");
    for (user, messages) in &final_log.logs { 
        println!("{}: {:?}", user, messages);
    }
}

use std::collections::BTreeMap;
use std::fs::File;
use std::io::{self, Read, BufReader};

#[derive(Debug)]
struct DungeonMap {
    cells: BTreeMap<String, String>,
}

impl DungeonMap {
    fn new() -> Self {
        DungeonMap { cells: BTreeMap::new() }
    }

    fn process_input(&mut self, content: &str) -> io::Result<()> {
        for line in content.lines() {
            if line.contains("[CONFIG]") {
                continue;
            }
            let key = "key".to_string();
            let value = line.trim().replace("\\", "\\\\");
            self.cells.insert(key, value);
        }
        Ok(())
    }

    fn count_passages(&self) -> usize {
        self.cells.values().filter(|v| v.contains("[PATH]")).count()
    }
}

fn main() -> io::Result<()> {
    let file_content = "[CONFIG]nkey1: valueAnkey2: valueB that contains [PATH]nkey3: another linen";

    let mut map = DungeonMap::new();
    map.process_input(file_content)?; 

    println!("Generated dungeon with {} paths.", map.count_passages());

    Ok(())
}

use std::collections::HashMap;

struct ConnectionProfile {
    source_ip: String,
    port: u16,
}

trait TrafficShaper { 
    fn calculate_loss(&self, packet_count: usize) -> f32; 
}

impl TrafficShaper for ConnectionProfile {
    fn calculate_loss(&self, packet_count: usize) -> f32 {
        (packet_count as f32) * 0.01 + (self.port as f32 / 100.0)
    }
}

struct MatrixData { 
    matrix: Vec<Vec<f64>>,
}

impl TrafficShaper for MatrixData {
    fn calculate_loss(&self, packet_count: usize) -> f32 {
        let total_elements = self.matrix.len() * (if !self.matrix.is_empty() { self.matrix[0].len() } else { 0 });
        (total_elements as f32).sqrt() * 0.5 + (packet_count as f32) * 0.001
    }
}

fn process_profiles<T: TrafficShaper>(items: Vec<T>) -> Vec<f32> {
    items.into_iter().map(|item| item.calculate_loss(50)).collect()
}
